no-auth` | `\\\"anonymous\\\"` | Admin |\\n//! | `Tailscale` | *(default)* | node name | from ACL tags |\\n//! | `Guest` | `--guest-role \u003crole\u003e` | `\\\"guest\\\"` | configured role |\\n//!\\n//! In `Tailscale` mode the server contacts the local Tailscale daemon over its\\n//! Unix socket (`/run/tailscale/tailscaled.sock` by default) and calls\\n//! `/localapi/v0/whois?addr=\u003cpeer\u003e` to resolve the connecting node's identity.\\n//! Resolved identities are cached by peer IP for the duration of\\n//! `--auth-cache-ttl-secs` (default 60 s).\\n//!\\n//! ACL tag → role mapping:\\n//! - `tag:axon-admin` → [`Role::Admin`]\\n//! - `tag:axon-write` / `tag:axon-agent` → [`Role::Write`]\\n//! - `tag:axon-read` → [`Role::Read`]\\n//! - no matching tag → `--tailscale-default-role` (default `read`)\\n//!\\n//! Connections that are not on the tailnet are rejected with HTTP 401 / gRPC\\n//! `UNAUTHENTICATED`.  If the Tailscale daemon is unreachable the server\\n//! returns HTTP 503 / gRPC `UNAVAILABLE`.\\n//!\\n//! # Request flow\\n//!\\n//! ```text\\n//! TCP accept\\n//!   └─ authenticate_http_request  (gateway.rs middleware)\\n//!        ├─ AuthContext::resolve_peer  →  Identity\\n//!        └─ insert Identity into request extensions\\n//!             └─ route handler\\n//!                  ├─ extract Extension\u003cIdentity\u003e\\n//!                  ├─ identity.require_read() / require_write() / require_admin()\\n//!                  └─ handler logic\\n//! ```\\n//!\\n//! gRPC follows the same pattern via [`service::AxonServiceImpl::authorize`].\\npub mod actor_scope;\\npub mod auth;\\nmod collection_listing;\\npub(crate) mod embedded_ui;\\npub mod control_plane;\\npub mod control_plane_routes;\\npub mod cors_config;\\npub mod user_roles;\\npub mod gateway;\\npub mod idempotency;\\npub(crate) mod mcp_http;\\npub mod mcp_stdio;\\npub mod rate_limit;\\npub mod schema_registry;\\npub mod serve;\\npub mod service;\\npub mod tenant_router;\\n\\npub use auth::{AuthContext, AuthMode, Identity, Role};\\npub use mcp_stdio::run_mcp_stdio;\\npub use service::AxonServiceImpl;\\n\",\"structuredPatch\":[{\"oldStart\":43,\"oldLines\":6,\"newStart\":43,\"newLines\":7,\"lines\":[\" //! gRPC follows the same pattern via [`service::AxonServiceImpl::authorize`].\",\" pub mod actor_scope;\",\" pub mod auth;\",\"+pub mod auth_pipeline;\",\" mod collection_listing;\",\" pub(crate) mod embedded_ui;\",\" pub mod control_plane;\"]},{\"oldStart\":60,\"oldLines\":5,\"newStart\":61,\"newLines\":6,\"lines\":[\" pub mod tenant_router;\",\" \",\" pub use auth::{AuthContext, AuthMode, Identity, Role};\",\"+pub use auth_pipeline::{InMemoryRevocationCache, JwtIssuer, jwt_verify_layer};\",\" pub use mcp_stdio::run_mcp_stdio;\",\" pub use service::AxonServiceImpl;\"]}],\"userModified\":false,\"replaceAll\":false}}\n{\"type\":\"assistant\",\"message\":{\"model\":\"claude-sonnet-4-6\",\"id\":\"msg_011zUAwXWxp7jsink5ubS91u\",\"type\":\"message\",\"role\":\"assistant\",\"content\":[{\"type\":\"tool_use\",\"id\":\"toolu_01FcFq7Ed8bhjLU3V5pQqBSY\",\"name\":\"TodoWrite\",\"input\":{\"todos\":[{\"content\":\"Add ResolvedIdentity, AuthError methods, Grants/GrantedDatabase helpers to axon-core/src/auth.rs\",\"status\":\"completed\",\"activeForm\":\"Adding auth types to axon-core\"},{\"content\":\"Add uuid dep + new trait methods (is_jti_revoked, get_user, get_tenant_member) to axon-storage\",\"status\":\"completed\",\"activeForm\":\"Adding storage trait methods\"},{\"content\":\"Implement new auth methods in MemoryStorageAdapter (memory.rs)\",\"status\":\"completed\",\"activeForm\":\"Implementing auth in MemoryStorageAdapter\"},{\"content\":\"Implement new auth methods in SqliteStorageAdapter and PostgresStorageAdapter\",\"status\":\"completed\",\"activeForm\":\"Implementing auth in Sqlite/Postgres adapters\"},{\"content\":\"Add jsonwebtoken dep + create axon-server/src/auth_pipeline.rs\",\"status\":\"completed\",\"activeForm\":\"Creating auth_pipeline.rs\"},{\"cont